final:
module shift_register (
    input clk,
    input shift,
    input [3:0] D,
    output reg Q3
);

reg [3:0] obf_reg_data;

always @(posedge clk) begin
    if (shift == 1'b0) begin
        obf_reg_data <= D;
    end else begin
        obf_reg_data <= {obf_reg_data[2:0], D[3]};
    end
end

assign Q3 = obf_reg_data[3];

endmodule
